1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	type Item = { type: string };
13	type Step = { items: Item[] };
14	type Scenario = { steps: Step[] };
15	
16	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
17	const BLOCK_BASE_PREMIUM = 60;
18	
19	export function processScenario(scenario: unknown): unknown {
20	  const { steps } = scenario as Scenario;
21	  const items = steps[0].items;
22	  const componentCountsByType = new Map<string, number>();
23	  for (const item of items) {
24	    if (COMPONENT_TYPES.has(item.type)) {
25	      componentCountsByType.set(
26	        item.type,
27	        (componentCountsByType.get(item.type) ?? 0) + 1,
28	      );
29	    }
30	  }
31	  const hasBlock = Array.from(componentCountsByType.values()).some(
32	    (count) => count === 3,
33	  );
34	  const basePremium = hasBlock
35	    ? BLOCK_BASE_PREMIUM
36	    : items.reduce(
37	        (sum, item) => sum + (BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0),
38	        0,
39	      );
40	  return { results: [{ premium: basePremium + PROCESSING_FEE }] };
41	}
